     3→import { useEffect, useState, useMemo } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Archive } from "lucide-react";
     6→import { SiteHeader } from "@/components/layout/site-header";
     7→import { ProCard } from "@/components/workspace/pro-card";
     8→import { FloatingDock } from "@/components/workspace/floating-dock";
     9→import { ProjectDetailOverlay } from "@/components/workspace/project-detail-overlay";
    10→import { useProfile } from "@/hooks/use-profile";
    11→import { useLanguageStore } from "@/store/language-store";
    12→import { cn } from "@/lib/utils";
    13→
    14→interface Project {
    15→    id: string;
    16→    title?: string;
    17→    text: string;
    18→    description?: string;
    19→    color?: string;
    20→    globalScore?: number;
    21→    recommendation?: string;
    22→    confidenceLevel?: string;
    23→    viabilityScore?: number;
    24→    classification?: string;
    25→    timestamp: string;
    26→    isDemo?: boolean;
    27→    isArchived?: boolean;
    28→    analysis?: any;
    29→}
    30→
    31→function getProjectDecision(p: Project): string {
    32→    return p.recommendation ?? p.classification ?? "DRAFT";
    33→}
    34→
    35→function getProjectTitle(p: Project): string {
    36→    return p.title ?? p.text;
    37→}
    38→
    39→export default function WorkspacePage() {
    40→    const router = useRouter();
    41→    const { profile } = useProfile();
    42→    const { t } = useLanguageStore();
    43→
    44→    const [projects, setProjects] = useState<Project[]>([]);
    45→    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    46→    const [searchQuery, setSearchQuery] = useState("");
    47→    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    48→    const [sortBy, setSortBy] = useState<string>("date");
    49→    const [showArchived, setShowArchived] = useState(false);
    50→
    51→    // Detail overlay state
    52→    const [detailProject, setDetailProject] = useState<Project | null>(null);
    53→    const [detailOpen, setDetailOpen] = useState(false);
    54→
    55→    // Initial Load Logic
    56→    useEffect(() => {
    57→        const currentIdea = localStorage.getItem("k3rn_active_project");
    58→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    59→
    60→        if (currentIdea) {
    61→            const idea = JSON.parse(currentIdea);
    62→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
    63→            if (!exists) {
    64→                const newProject: Project = {
    65→                    id: idea.id || crypto.randomUUID(),
    66→                    title: idea.title,
    67→                    text: idea.text || "",
    68→                    description: idea.description,
    69→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
    70→                    recommendation: idea.recommendation ?? idea.analysis?.classification,
    71→                    confidenceLevel: idea.confidenceLevel,
    72→                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
    73→                    classification: idea.classification ?? idea.analysis?.classification,
    74→                    timestamp: idea.timestamp,
    75→                    isDemo: idea.isDemo,
    76→                    analysis: idea.analysis,
    77→                };
    78→                storedProjects.unshift(newProject);
    79→                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
    80→                localStorage.removeItem("k3rn_active_project");
    81→            }
    82→        }
    83→
    84→        if (storedProjects.length === 0) {
    85→            const mocks: Project[] = [
    86→                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance.", analysis: { axes: [{ label: "Probleme", score: 9 }, { label: "Marche", score: 8 }, { label: "Differenciation", score: 10 }, { label: "Faisabilite", score: 8 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 9 }], synthesis: "Ce projet presente un potentiel exceptionnel. Le marche de la logistique drone est en pleine expansion avec un CAGR de 28%. La differenciation technique est maximale grace a l'integration d'IA pour le pathfinding et la maintenance predictive. Le business model SaaS assure des revenus recurrents. Recommandation : accelerer le developpement du MVP et securiser un premier contrat pilote.", risks: ["Reglementation aerienne complexe et en evolution — risque de delais reglementaires", "Cout d'infrastructure eleve pour le deploiement initial (stations de charge, communication)", "Competition potentielle des geants tech (Amazon Prime Air, Wing/Alphabet)", "Dependance aux conditions meteorologiques pour les operations quotidiennes"] } },
    87→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand.", analysis: { synthesis: "Le concept de tokenisation des brevets sur blockchain ne repond pas a un besoin reel du marche. Les acteurs industriels privilegient les canaux traditionnels de gestion de PI.", risks: ["Absence de demande marche validee", "Complexite juridique de la tokenisation de PI", "Modele economique non viable a long terme"] } },
    88→                { id: "3", title: "AI Film Script Generator", text: "IA generative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", confidenceLevel: "MEDIUM", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure.", analysis: { synthesis: "L'outil montre un potentiel creatif interessant mais necessite une structuration plus poussee du workflow narratif. Le marche de l'IA creative est en croissance rapide.", risks: ["Qualite narrative encore insuffisante pour un usage professionnel", "Concurrence forte des outils existants (ChatGPT, Jasper)", "Questions ethiques sur la propriete intellectuelle generee par IA"] } },
    89→                { id: "4", title: "MeowNet - Social Network for Cats", text: "Reseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", confidenceLevel: "LOW", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
    90→                { id: "5", title: "Quantum Encryption Key", text: "Cle de chiffrement quantique", globalScore: 88, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era.", analysis: { axes: [{ label: "Probleme", score: 10 }, { label: "Marche", score: 9 }, { label: "Differenciation", score: 8 }, { label: "Faisabilite", score: 7 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 8 }], synthesis: "Infrastructure de securite critique pour l'ere post-quantique. Le marche fintech est pret pour cette transition. La faisabilite technique est le principal defi.", risks: ["Complexite technique de l'implementation quantique", "Cout de R&D eleve avant commercialisation", "Risque de timing — marche pas encore pret massivement"] } },
    91→            ];
    92→            setProjects(mocks);
    93→        } else {
    94→            setProjects(storedProjects);
    95→        }
    96→    }, []);
    97→
    98→    const filteredProjects = useMemo(() => {
    99→        let result = projects.filter((p) => {
   100→            // Filter by archived status
   101→            const matchesArchiveStatus = showArchived ? p.isArchived === true : p.isArchived !== true;
   102→
   103→            const q = searchQuery.toLowerCase();
   104→            const matchesSearch =
   105→                getProjectTitle(p).toLowerCase().includes(q) ||
   106→                p.text.toLowerCase().includes(q) ||
   107→                getProjectDecision(p).toLowerCase().includes(q);
   108→
   109→            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;
   110→
   111→            return matchesArchiveStatus && matchesSearch && matchesFilter;
   112→        });
   113→
   114→        if (sortBy === "score") {
   115→            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
   116→        } else {
   117→            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
   118→        }
   119→
   120→        return result;
   121→    }, [projects, searchQuery, activeFilter, sortBy, showArchived]);
   122→
   123→    // Welcome hero stats
   124→    const goCount = projects.filter((p) => getProjectDecision(p) === "GO").length;
   125→    const attentionCount = projects.filter((p) => {
   126→        const d = getProjectDecision(p);
   127→        return d === "EXPLORE" || d === "KILL";
   128→    }).length;
   129→
   130→    // Save handler for detail overlay
   131→    function handleSaveProject(id: string, updates: { title?: string; description?: string }) {
   132→        const updated = projects.map((p) =>
   133→            p.id === id ? { ...p, ...updates } : p
   134→        );
   135→        setProjects(updated);
   136→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   137→    }
   138→
   139→    // Archive handler
   140→    function handleArchive(id: string) {
   141→        const updated = projects.map((p) =>
   142→            p.id === id ? { ...p, isArchived: true } : p
   143→        );
   144→        setProjects(updated);
   145→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   146→        setDetailOpen(false);
   147→        setDetailProject(null);
   148→    }
   149→
   150→    // Unarchive handler
   151→    function handleUnarchive(id: string) {
   152→        const updated = projects.map((p) =>
   153→            p.id === id ? { ...p, isArchived: false } : p
   154→        );
   155→        setProjects(updated);
   156→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   157→        setDetailOpen(false);
   158→        setDetailProject(null);
   159→    }
   160→
   161→    // Delete handler
   162→    function handleDelete(id: string) {
   163→        const updated = projects.filter((p) => p.id !== id);
   164→        setProjects(updated);
   165→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   166→        setDetailOpen(false);
   167→        setDetailProject(null);
   168→    }
   169→
   170→    return (
   171→        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
   172→            <SiteHeader variant="app" />
   173→
   174→            <main className="relative z-[1] flex-1 pt-12 pb-40 px-8 w-full max-w-[1400px] mx-auto">
   175→
   176→                {/* Welcome Hero */}
   177→                <div
   178→                    className="mb-12 rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
   179→                    style={{
   180→                        background: "var(--color-bg-secondary)",
   181→                        border: "1px solid var(--color-border-subtle)",
   182→                        boxShadow: "inset 0 1px 0 rgba(0,0,0,0.2), inset 0 -1px 0 rgba(255,255,255,0.02)",
   183→                    }}
   184→                >
   185→                    <h1 className="text-[2.5rem] font-light text-white tracking-[-0.02em] leading-[1.1] mb-3">
   186→                        {t.workspace.welcome}, {profile?.display_name || t.workspace.defaultUser}.
   187→                    </h1>
   188→                    <div className="flex items-center justify-between">
   189→                        <p className="text-base text-[--color-text-muted] flex items-center gap-2">
   190→                            <strong className="text-[--color-text-secondary] font-medium">{projects.filter(p => !p.isArchived).length}</strong> dossier{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""} actif{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""}
   191→                            {" "}&middot;{" "}
   192→                            <strong className="text-[--color-text-secondary] font-medium">{goCount}</strong> projet{goCount !== 1 ? "s" : ""} valide{goCount !== 1 ? "s" : ""} GO
   193→                            {" "}&middot;{" "}
   194→                            <strong className="text-[--color-text-secondary] font-medium">{attentionCount}</strong> necessite{attentionCount !== 1 ? "nt" : ""} votre attention
   195→                        </p>
   196→                        <button
   197→                            onClick={() => setShowArchived(!showArchived)}
   198→                            className="group inline-flex items-center gap-2 px-4 py-2 bg-transparent text-[--color-text-muted] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-300 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong] hover:scale-[1.02] active:scale-[0.98]"
   199→                        >
   200→                            <Archive className="w-4 h-4 transition-transform duration-300 group-hover:scale-110" />
   201→                            {showArchived ? "Dossiers actifs" : "Dossiers archivés disponibles"}
   202→                        </button>
   203→                    </div>
   204→                </div>
   205→
   206→                {/* Grid */}
   207→                <div className={cn(
   208→                    "animate-in fade-in zoom-in-95 duration-500",
   209→                    viewMode === "grid"
   210→                        ? "grid gap-6"
   211→                        : "grid grid-cols-1 gap-4"
   212→                )}
   213→                    style={viewMode === "grid" ? { gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))" } : undefined}
   214→                >
   215→                    {/* New Project Card - Only show when NOT in archived view */}
   216→                    {!showArchived && (
   217→                        <ProCard
   218→                            isNew
   219→                            onClick={() => router.push('/capture')}
   220→                        />
   221→                    )}
   222→
   223→                    {/* Project Cards */}
   224→                    {filteredProjects.map((project) => (
   225→                        <ProCard
   226→                            key={project.id}
   227→                            project={project}
   228→                            onClick={() => {
   229→                                setDetailProject(project);
   230→                                setDetailOpen(true);
   231→                            }}
   232→                        />
   233→                    ))}
   234→                </div>
   235→            </main>
   236→
   237→            {/* Floating Command Dock */}
   238→            <FloatingDock
   239→                viewMode={viewMode}
   240→                setViewMode={setViewMode}
   241→                searchQuery={searchQuery}
   242→                setSearchQuery={setSearchQuery}
   243→                activeFilter={activeFilter}
   244→                setActiveFilter={setActiveFilter}
   245→                sortBy={sortBy}
   246→                setSortBy={setSortBy}
   247→                onNewProject={() => router.push('/capture')}
   248→            />
   249→
   250→            {/* Project Detail Overlay */}
   251→            <ProjectDetailOverlay
   252→                project={detailProject}
   253→                open={detailOpen}
   254→                onClose={() => {
   255→                    setDetailOpen(false);
   256→                    setDetailProject(null);
   257→                }}
   258→                onSave={handleSaveProject}
   259→                onArchive={handleArchive}
   260→                onUnarchive={handleUnarchive}
   261→                onDelete={handleDelete}
   262→            />
   263→        </div>
   264→    );
   265→}
