     3→import { useState, useRef, useEffect } from "react";
     4→import { Paperclip, Link as LinkIcon, Mic, X, Sparkles, ArrowDownLeft } from "lucide-react";
     5→import { useRouter } from "next/navigation";
     6→import Link from "next/link";
     7→import { cn } from "@/lib/utils";
     8→import { toast } from "sonner";
     9→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
    10→import { useSpeechRecognition } from "@/hooks/use-speech-recognition";
    11→// import { UserNav } from "@/components/layout/user-nav"; 
    12→import { AuthModal } from "@/components/auth/auth-modal";
    13→import { AnalysisResults } from "@/components/capture/analysis-results";
    14→import { useLanguageStore } from "@/store/language-store";
    15→import { SiteHeader } from "@/components/layout/site-header";
    16→
    17→export default function CapturePage() {
    18→    const router = useRouter();
    19→    const { t, currentLang } = useLanguageStore();
    20→
    21→    // State
    22→    const [input, setInput] = useState("");
    23→    const [files, setFiles] = useState<File[]>([]);
    24→    const [links, setLinks] = useState<string[]>([]);
    25→    const [viewMode, setViewMode] = useState<"INPUT" | "ANALYZING">("INPUT");
    26→    const [isVoice, setIsVoice] = useState(false);
    27→
    28→    // UI State
    29→    const [linkInput, setLinkInput] = useState("");
    30→    const [isLinkOpen, setIsLinkOpen] = useState(false);
    31→
    32→    // Refs
    33→    const textareaRef = useRef<HTMLTextAreaElement>(null);
    34→    const fileInputRef = useRef<HTMLInputElement>(null);
    35→
    36→    const { isRecording, toggleRecording } = useSpeechRecognition({
    37→        onFinal: (text) => {
    38→            setIsVoice(true);
    39→            setInput((prev) => {
    40→                const needsSpace = prev.length > 0 && !prev.endsWith(" ") && !prev.endsWith("\n");
    41→                return prev + (needsSpace ? " " : "") + text;
    42→            });
    43→        },
    44→        onError: (err) => toast.error("Erreur vocale", { description: err })
    45→    });
    46→
    47→    useEffect(() => {
    48→        document.documentElement.lang = currentLang.toLowerCase();
    49→    }, [currentLang]);
    50→
    51→    const handleSubmit = async () => {
    52→        if (!input.trim() && files.length === 0 && links.length === 0) return;
    53→        setViewMode("ANALYZING");
    54→        if (typeof window !== "undefined") {
    55→            const payload = {
    56→                text: input,
    57→                files: files.map(f => ({ name: f.name, type: f.type, size: f.size })),
    58→                links: links,
    59→                timestamp: new Date().toISOString()
    60→            };
    61→            localStorage.setItem("k3rn_current_idea", JSON.stringify(payload));
    62→        }
    63→    };
    64→
    65→    const handleReset = () => {
    66→        setViewMode("INPUT");
    67→        setInput("");
    68→        setFiles([]);
    69→        setLinks([]);
    70→        setIsVoice(false);
    71→    };
    72→
    73→    const handleKeyDown = (e: React.KeyboardEvent) => {
    74→        if ((e.metaKey || e.ctrlKey) && e.key === "Enter") {
    75→            handleSubmit();
    76→        }
    77→    };
    78→
    79→    const handleAttachFile = () => {
    80→        fileInputRef.current?.click();
    81→    };
    82→
    83→    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    84→        if (e.target.files && e.target.files.length > 0) {
    85→            const newFile = e.target.files[0];
    86→            setFiles(prev => [...prev, newFile]);
    87→            toast.success("Fichier joint", { description: newFile.name });
    88→            if (fileInputRef.current) fileInputRef.current.value = "";
    89→        }
    90→    };
    91→
    92→    const removeFile = (index: number) => {
    93→        setFiles(prev => prev.filter((_, i) => i !== index));
    94→    };
    95→
    96→    const addLink = () => {
    97→        if (!linkInput.trim()) return;
    98→        setLinks(prev => [...prev, linkInput]);
    99→        toast.success("Lien ajouté");
   100→        setLinkInput("");
   101→        setIsLinkOpen(false);
   102→    };
   103→
   104→    const removeLink = (index: number) => {
   105→        setLinks(prev => prev.filter((_, i) => i !== index));
   106→    };
   107→
   108→    // Focus on mount
   109→    useEffect(() => {
   110→        if (viewMode === "INPUT") {
   111→            textareaRef.current?.focus();
   112→        }
   113→    }, [viewMode]);
   114→
   115→    const hasContent = input.trim().length > 0 || files.length > 0 || links.length > 0;
   116→
   117→    return (
   118→        <div className="min-h-screen bg-background text-foreground flex flex-col font-sans selection:bg-[#F75105]/30">
   119→            <SiteHeader variant="app" />
   120→            <AuthModal />
   121→
   122→            {/* Main Content using Flex to Center */}
   123→            <main className="flex-1 w-full mx-auto px-6 flex flex-col items-center justify-center gap-12 pb-24">
   124→
   125→                {/* Hero Text (Only in Input Mode) */}
   126→                {viewMode === "INPUT" && (
   127→                    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col gap-6 text-center w-full items-center">
   128→                        <h1 className="text-6xl md:text-7xl font-light text-white tracking-tight leading-[1.0] font-sans whitespace-nowrap">
   129→                            {t?.capture?.hero || "Capture Your Vision"}
   130→                        </h1>
   131→                        <p className="text-[#A0A3AB] font-light text-lg tracking-wide leading-relaxed">
   132→                            Donnons vie à vos ambitions.
   133→                        </p>
   134→                    </div>
   135→                )}
   136→
   137→                {/* INPUT CARD - MODERN ROUNDED (Radius 24px) */}
   138→                {viewMode === "INPUT" && (
   139→                    <div className="w-full max-w-3xl bg-[--bg-card] rounded-[24px] border border-[--border-default] p-8 shadow-2xl relative overflow-visible transition-all duration-300 hover:border-[--border-strong] focus-within:border-[#F75105] animate-in zoom-in-95 backdrop-blur-sm group/card">
   140→
   141→                        {/* Textarea */}
   142→                        <textarea
   143→                            ref={textareaRef}
   144→                            value={input}
   145→                            onChange={(e) => setInput(e.target.value)}
   146→                            onKeyDown={handleKeyDown}
   147→                            className="w-full h-40 bg-transparent resize-none outline-none text-xl text-white placeholder:text-[#5D5C5B] font-light leading-relaxed scrollbar-hide"
   148→                            placeholder={t?.capture?.placeholder || "Describe your idea..."}
   149→                            autoFocus
   150→                        />
   151→
   152→                        {/* Attachments Preview */}
   153→                        {(files.length > 0 || links.length > 0) && (
   154→                            <div className="flex flex-wrap gap-2 mt-4 mb-4 pt-4 border-t border-[--border-subtle]">
   155→                                {files.map((file, index) => (
   156→                                    <div
   157→                                        key={index}
   158→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   159→                                    >
   160→                                        <Paperclip className="w-3 h-3 text-[#5D5C5B]" />
   161→                                        <span className="max-w-[150px] truncate">{file.name}</span>
   162→                                        <button
   163→                                            onClick={() => removeFile(index)}
   164→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   165→                                        >
   166→                                            <X className="w-3 h-3" />
   167→                                        </button>
   168→                                    </div>
   169→                                ))}
   170→                                {links.map((link, index) => (
   171→                                    <div
   172→                                        key={index}
   173→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   174→                                    >
   175→                                        <LinkIcon className="w-3 h-3 text-[#F75105]" />
   176→                                        <span className="max-w-[150px] truncate">{link}</span>
   177→                                        <button
   178→                                            onClick={() => removeLink(index)}
   179→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   180→                                        >
   181→                                            <X className="w-3 h-3" />
   182→                                        </button>
   183→                                    </div>
   184→                                ))}
   185→                            </div>
   186→                        )}
   187→
   188→                        {/* Hidden File Input */}
